const DEFAULT_POLL_INTERVAL_MS = 1500;
/**
 * Continuously poll the dataset's agent-event channel and invoke `onEvent`
 * for each new event the server hands us. Each poll request is short-lived
 * (Vercel-friendly): no SSE, no long-poll, just a normal GET that returns
 * any newly-claimed `dataset.agent.event` tickets since the last cursor.
 *
 * The loop runs until `abortSignal` fires. Network errors are swallowed and
 * retried on the next tick — transient connectivity should not surface as a
 * fatal terminal-channel close, since `startDataset.ts` listens to a separate
 * (terminal) channel for the user clicking Done.
 */
export async function pollAgentEvents(opts) {
    const interval = opts.intervalMs ?? DEFAULT_POLL_INTERVAL_MS;
    let since = opts.startCursor ? opts.startCursor : null;
    while (!opts.abortSignal.aborted) {
        try {
            const url = new URL(`${opts.serviceUrl}/api/plugin/datasets/${encodeURIComponent(opts.datasetId)}/agent-events`);
            if (since) {
                url.searchParams.set("since", since);
            }
            const res = await fetch(url.toString(), {
                headers: { Authorization: `Bearer ${opts.apiKey}` },
                signal: opts.abortSignal,
            });
            if (res.ok) {
                const body = (await res.json());
                for (const event of body.events) {
                    opts.onEvent(event);
                }
                since = body.nextSince;
            }
            else if (opts.onError) {
                opts.onError(new Error(`agent-events poll failed (${res.status})`));
            }
        }
        catch (err) {
            if (opts.abortSignal.aborted) {
                return;
            }
            if (opts.onError) {
                opts.onError(err instanceof Error ? err : new Error(String(err)));
            }
        }
        await new Promise((resolve) => {
            const timer = setTimeout(resolve, interval);
            opts.abortSignal.addEventListener("abort", () => {
                clearTimeout(timer);
                resolve();
            }, { once: true });
        });
    }
}
